-- Schema: workbench
CREATE SCHEMA IF NOT EXISTS workbench;

CREATE OR REPLACE FUNCTION workbench.ack_resolved(p_module text)
 RETURNS TABLE(id integer, to_module text, msg_type text, subject text, resolution text)
 LANGUAGE sql
AS $function$
  UPDATE workbench.agent_message
    SET acknowledged_at = resolved_at
    WHERE from_module = p_module
      AND status = 'resolved'
      AND (acknowledged_at IS NULL OR resolved_at > acknowledged_at)
    RETURNING agent_message.id, agent_message.to_module, agent_message.msg_type,
              agent_message.subject, agent_message.resolution;
$function$;
COMMENT ON FUNCTION workbench.ack_resolved(text) IS 'Auto-acknowledge resolved sent messages — used by Stop hook';

CREATE OR REPLACE FUNCTION workbench.api_hooks(p_module text DEFAULT NULL::text)
 RETURNS TABLE(id integer, module text, tool text, action text, allowed boolean, reason text, created_at timestamp with time zone)
 LANGUAGE sql
 STABLE
AS $function$
  SELECT h.id, h.module, h.tool, h.action, h.allowed, h.reason, h.created_at
    FROM workbench.hook_log h
   WHERE p_module IS NULL OR h.module = p_module
   ORDER BY h.created_at DESC
   LIMIT 100;
$function$;
COMMENT ON FUNCTION workbench.api_hooks(text) IS 'List hook events, optionally filtered by module — used by GET /api/hooks';

CREATE OR REPLACE FUNCTION workbench.api_messages(p_module text DEFAULT NULL::text)
 RETURNS TABLE(id integer, from_module text, to_module text, msg_type text, subject text, body text, status text, resolution text, priority text, reply_to integer, payload jsonb, result jsonb, created_at timestamp with time zone, resolved_at timestamp with time zone)
 LANGUAGE sql
 STABLE
AS $function$
  SELECT m.id, m.from_module, m.to_module, m.msg_type, m.subject, m.body,
         m.status, m.resolution, m.priority, m.reply_to,
         m.payload, m.result, m.created_at, m.resolved_at
    FROM workbench.agent_message m
   WHERE (p_module IS NULL OR m.from_module = p_module OR m.to_module = p_module)
   ORDER BY m.created_at DESC
   LIMIT 100;
$function$;
COMMENT ON FUNCTION workbench.api_messages(text) IS 'REST API for messages — includes task delegation columns';

CREATE OR REPLACE FUNCTION workbench.api_sessions()
 RETURNS TABLE(module text, status text, pid integer, started_at timestamp with time zone, ended_at timestamp with time zone, last_activity timestamp with time zone)
 LANGUAGE sql
 STABLE
AS $function$
  SELECT s.module, s.status, s.pid, s.started_at, s.ended_at, s.last_activity
    FROM workbench.agent_session s
   ORDER BY s.started_at DESC
   LIMIT 50;
$function$;
COMMENT ON FUNCTION workbench.api_sessions() IS 'List recent agent sessions — used by GET /api/agents';

