CREATE OR REPLACE FUNCTION workbench.get_index()
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_new_msg   integer;
  v_pending   integer;
  v_open_iss  integer;
  v_tools     integer;
  v_html      text;
BEGIN
  SELECT count(*) INTO v_new_msg
    FROM workbench.agent_message WHERE status = 'new';
  SELECT count(*) INTO v_pending
    FROM workbench.agent_message WHERE status = 'acknowledged';
  SELECT count(*) INTO v_open_iss
    FROM workbench.issue_report WHERE status IN ('open','acknowledged');
  SELECT count(*) INTO v_tools
    FROM workbench.toolbox_tool;

  v_html := pgv.grid(
    pgv.stat(pgv.t('workbench.stat_new_msg'), v_new_msg::text),
    pgv.stat(pgv.t('workbench.stat_pending'), v_pending::text),
    pgv.stat(pgv.t('workbench.stat_issues'), v_open_iss::text),
    pgv.stat(pgv.t('workbench.stat_tools'), v_tools::text)
  );

  v_html := v_html || '<h3>' || pgv.t('workbench.title_recent_msg') || '</h3>';
  v_html := v_html || '<md data-page="10">' || E'\n';
  v_html := v_html || '| # | De | A | Type | Sujet | Statut |' || E'\n';
  v_html := v_html || '|---|----|----|------|-------|--------|' || E'\n';

  SELECT v_html || coalesce(string_agg(
    '| <button type="button" data-form-dialog="msg-detail" data-src="/message?p_id=' || m.id || '" class="outline pgv-btn-sm">' || m.id || '</button> '
    || '| ' || m.from_module
    || ' | ' || m.to_module
    || ' | ' || pgv.badge(m.msg_type, CASE m.msg_type
        WHEN 'task' THEN 'info'
        WHEN 'bug_report' THEN 'danger'
        WHEN 'feature_request' THEN 'warning'
        WHEN 'info' THEN 'muted'
        ELSE 'muted' END)
    || ' | ' || pgv.md_esc(m.subject, 60)
    || ' | ' || pgv.badge(m.status, CASE m.status
        WHEN 'new' THEN 'warning'
        WHEN 'acknowledged' THEN 'info'
        WHEN 'resolved' THEN 'success'
        ELSE 'muted' END)
    || ' |', E'\n'
    ORDER BY m.id DESC
  ), '') || E'\n</md>'
    || '<dialog id="msg-detail" class="pgv-form-dialog"><article class="pgv-form-dialog-article">'
    || '<header class="pgv-form-dialog-header"><strong>' || pgv.t('workbench.title_message_detail') || '</strong>'
    || '<button class="pgv-form-dialog-close" onclick="this.closest(''dialog'').close()">&times;</button></header>'
    || '<div class="pgv-form-dialog-body"></div>'
    || '</article></dialog>'
  INTO v_html
  FROM workbench.agent_message m;

  RETURN v_html;
END;
$function$;
COMMENT ON FUNCTION workbench.get_index() IS 'Workbench dashboard — messaging stats, recent messages';

CREATE OR REPLACE FUNCTION workbench.get_issues()
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_open    integer;
  v_ack     integer;
  v_closed  integer;
  v_html    text;
BEGIN
  SELECT count(*) FILTER (WHERE status = 'open'),
         count(*) FILTER (WHERE status = 'acknowledged'),
         count(*) FILTER (WHERE status IN ('resolved','closed'))
    INTO v_open, v_ack, v_closed
    FROM workbench.issue_report;

  v_html := pgv.grid(
    pgv.stat('Ouvertes', v_open::text),
    pgv.stat('En cours', v_ack::text),
    pgv.stat('Resolues', v_closed::text)
  );

  v_html := v_html || '<md data-page="20">' || E'\n';
  v_html := v_html || '| # | Type | Module | Description | Statut | Date |' || E'\n';
  v_html := v_html || '|---|------|--------|-------------|--------|------|' || E'\n';

  SELECT v_html || coalesce(string_agg(
    '| ' || i.id
    || ' | ' || pgv.badge(i.issue_type, CASE i.issue_type WHEN 'bug' THEN 'danger' WHEN 'enhancement' THEN 'info' ELSE 'muted' END)
    || ' | ' || coalesce(i.module, '-')
    || ' | ' || pgv.md_esc(i.description)
    || ' | ' || pgv.badge(i.status, CASE i.status WHEN 'open' THEN 'warning' WHEN 'acknowledged' THEN 'info' WHEN 'resolved' THEN 'success' ELSE 'muted' END)
    || ' | ' || to_char(i.created_at, 'DD/MM HH24:MI')
    || ' |', E'\n'
    ORDER BY i.id DESC
  ), pgv.t('workbench.label_no_issues')) || E'\n</md>'
  INTO v_html
  FROM workbench.issue_report i;

  RETURN v_html;
END;
$function$;
COMMENT ON FUNCTION workbench.get_issues() IS 'Issue tracker listing with status stats';

CREATE OR REPLACE FUNCTION workbench.get_message(p_id integer)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_msg    record;
  v_html   text;
  v_issue  record;
BEGIN
  SELECT * INTO v_msg FROM workbench.agent_message WHERE id = p_id;
  IF NOT FOUND THEN
    RETURN pgv.empty(pgv.t('workbench.label_no_messages'));
  END IF;

  v_html := pgv.breadcrumb(VARIADIC ARRAY[pgv.t('workbench.nav_messages'), pgv.call_ref('get_messages'), '#' || p_id::text]);

  v_html := v_html || pgv.grid(
    pgv.stat('Type', pgv.badge(v_msg.msg_type, CASE v_msg.msg_type
        WHEN 'task' THEN 'info'
        WHEN 'bug_report' THEN 'danger'
        WHEN 'feature_request' THEN 'warning'
        WHEN 'info' THEN 'muted'
        ELSE 'muted' END)),
    pgv.stat('Statut', pgv.badge(v_msg.status, CASE v_msg.status
        WHEN 'new' THEN 'warning'
        WHEN 'acknowledged' THEN 'info'
        WHEN 'resolved' THEN 'success'
        ELSE 'muted' END)),
    pgv.stat('Priorite', CASE WHEN v_msg.priority = 'high' THEN pgv.badge('HIGH','danger') ELSE 'normal' END),
    pgv.stat('Date', to_char(v_msg.created_at, 'DD/MM/YYYY HH24:MI'))
  );

  v_html := v_html || '<md>' || E'\n';
  v_html := v_html || '| Champ | Valeur |' || E'\n';
  v_html := v_html || '|-------|--------|' || E'\n';
  v_html := v_html || '| De | ' || pgv.md_esc(v_msg.from_module) || ' |' || E'\n';
  v_html := v_html || '| A | ' || pgv.md_esc(v_msg.to_module) || ' |' || E'\n';
  v_html := v_html || '| Sujet | ' || pgv.md_esc(v_msg.subject, 120) || ' |' || E'\n';
  IF v_msg.body IS NOT NULL THEN
    v_html := v_html || '| Corps | ' || pgv.md_esc(v_msg.body, 200) || ' |' || E'\n';
  END IF;
  IF v_msg.resolution IS NOT NULL THEN
    v_html := v_html || '| Resolution | ' || pgv.md_esc(v_msg.resolution, 200) || ' |' || E'\n';
  END IF;
  v_html := v_html || '</md>' || E'\n';

  SELECT * INTO v_issue FROM workbench.issue_report WHERE message_id = p_id;
  IF FOUND THEN
    v_html := v_html || '<h4>Issue liee #' || v_issue.id || '</h4>';
    v_html := v_html || '<md>' || E'\n';
    v_html := v_html || '| Champ | Valeur |' || E'\n';
    v_html := v_html || '|-------|--------|' || E'\n';
    v_html := v_html || '| Type | ' || pgv.badge(v_issue.issue_type, CASE v_issue.issue_type WHEN 'bug' THEN 'danger' ELSE 'info' END) || ' |' || E'\n';
    v_html := v_html || '| Module | ' || coalesce(v_issue.module, '-') || ' |' || E'\n';
    v_html := v_html || '| Statut | ' || pgv.badge(v_issue.status, CASE v_issue.status WHEN 'open' THEN 'warning' WHEN 'resolved' THEN 'success' ELSE 'info' END) || ' |' || E'\n';
    v_html := v_html || '| Description | ' || pgv.md_esc(v_issue.description, 200) || ' |' || E'\n';
    v_html := v_html || '</md>' || E'\n';
  END IF;

  v_html := v_html || '<h4>Fil de discussion</h4>';
  v_html := v_html || '<md>' || E'\n';
  v_html := v_html || '| # | De | A | Sujet | Statut | Date |' || E'\n';
  v_html := v_html || '|---|----|---|-------|--------|------|' || E'\n';

  SELECT v_html || coalesce(string_agg(
    '| [' || r.id || '](' || pgv.call_ref('get_message', jsonb_build_object('p_id', r.id)) || ')'
    || ' | ' || pgv.md_esc(r.from_module)
    || ' | ' || pgv.md_esc(r.to_module)
    || ' | ' || pgv.md_esc(r.subject)
    || ' | ' || pgv.badge(r.status, CASE r.status
        WHEN 'new' THEN 'warning'
        WHEN 'acknowledged' THEN 'info'
        WHEN 'resolved' THEN 'success'
        ELSE 'muted' END)
    || ' | ' || to_char(r.created_at, 'DD/MM HH24:MI')
    || ' |', E'\n'
    ORDER BY r.id
  ), '') || E'\n</md>'
  INTO v_html
  FROM workbench.agent_message r
  WHERE r.reply_to = p_id OR r.id = p_id;

  IF v_msg.payload IS NOT NULL THEN
    v_html := v_html || '<h4>Payload</h4><pre>' || jsonb_pretty(v_msg.payload) || '</pre>';
  END IF;
  IF v_msg.result IS NOT NULL THEN
    v_html := v_html || '<h4>Result</h4><pre>' || jsonb_pretty(v_msg.result) || '</pre>';
  END IF;

  RETURN v_html;
END;
$function$;
COMMENT ON FUNCTION workbench.get_message(integer) IS 'Message detail view with linked issue and reply chain';

CREATE OR REPLACE FUNCTION workbench.get_messages(p_module text DEFAULT NULL::text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_total   integer;
  v_new     integer;
  v_ack     integer;
  v_resolved integer;
  v_html    text;
BEGIN
  SELECT count(*),
         count(*) FILTER (WHERE status = 'new'),
         count(*) FILTER (WHERE status = 'acknowledged'),
         count(*) FILTER (WHERE status = 'resolved')
    INTO v_total, v_new, v_ack, v_resolved
    FROM workbench.agent_message
   WHERE p_module IS NULL
      OR from_module = p_module
      OR to_module = p_module;

  v_html := pgv.grid(
    pgv.stat('Total', v_total::text),
    pgv.stat('Nouveaux', v_new::text),
    pgv.stat('En cours', v_ack::text),
    pgv.stat('Resolus', v_resolved::text)
  );

  v_html := v_html || '<md data-page="20">' || E'\n';
  v_html := v_html || '| # | De | A | Type | Priorite | Sujet | Statut | Date |' || E'\n';
  v_html := v_html || '|---|----|----|------|----------|-------|--------|------|' || E'\n';

  SELECT v_html || coalesce(string_agg(
    '| <button type="button" data-form-dialog="msg-detail" data-src="/message?p_id=' || m.id || '" class="outline pgv-btn-sm">' || m.id || '</button>'
    || ' | ' || m.from_module
    || ' | ' || m.to_module
    || ' | ' || pgv.badge(m.msg_type, CASE m.msg_type
        WHEN 'task' THEN 'info'
        WHEN 'bug_report' THEN 'danger'
        WHEN 'feature_request' THEN 'warning'
        WHEN 'breaking_change' THEN 'danger'
        WHEN 'info' THEN 'muted'
        ELSE 'muted' END)
    || ' | ' || CASE WHEN m.priority = 'high' THEN pgv.badge('HIGH','danger') ELSE 'normal' END
    || ' | ' || pgv.md_esc(m.subject, 60)
    || ' | ' || pgv.badge(m.status, CASE m.status
        WHEN 'new' THEN 'warning'
        WHEN 'acknowledged' THEN 'info'
        WHEN 'resolved' THEN 'success'
        ELSE 'muted' END)
    || ' | ' || to_char(m.created_at, 'DD/MM HH24:MI')
    || ' |', E'\n'
    ORDER BY m.id DESC
  ), '') || E'\n</md>'
    || '<dialog id="msg-detail" class="pgv-form-dialog"><article class="pgv-form-dialog-article">'
    || '<header class="pgv-form-dialog-header"><strong>' || pgv.t('workbench.title_message_detail') || '</strong>'
    || '<button class="pgv-form-dialog-close" onclick="this.closest(''dialog'').close()">&times;</button></header>'
    || '<div class="pgv-form-dialog-body"></div>'
    || '</article></dialog>'
  INTO v_html
  FROM workbench.agent_message m
  WHERE p_module IS NULL
     OR m.from_module = p_module
     OR m.to_module = p_module;

  RETURN v_html;
END;
$function$;
COMMENT ON FUNCTION workbench.get_messages(text) IS 'List all inter-module messages with filters and stats';

CREATE OR REPLACE FUNCTION workbench.get_primitives()
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
  -- Switch prefix so pgv_qa call_ref() resolves to pgv_qa schema
  PERFORM set_config('pgv.route_prefix', '/pgv_qa', true);

  RETURN pgv.tabs(
    'Composants',   pgv_qa.get_atoms(),
    'Tables',       pgv_qa.get_tables(),
    'Formulaires',  pgv_qa.get_forms(),
    'Dialogs',      pgv_qa.get_dialogs(),
    'Toasts',       pgv_qa.get_toast(),
    'SVG',          pgv_qa.get_svg(),
    'Erreurs',      pgv_qa.get_errors()
  );
END;
$function$;
COMMENT ON FUNCTION workbench.get_primitives() IS 'UI primitives catalog — wraps pgv_qa showcase pages in tabs';

CREATE OR REPLACE FUNCTION workbench.get_tool(p_name text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_tool   record;
  v_html   text;
  v_params jsonb;
  v_key    text;
  v_prop   jsonb;
BEGIN
  SELECT * INTO v_tool FROM workbench.toolbox_tool WHERE tool_name = p_name;
  IF NOT FOUND THEN
    RETURN pgv.empty(pgv.t('workbench.label_no_tools'));
  END IF;

  v_html := pgv.breadcrumb(VARIADIC ARRAY[pgv.t('workbench.nav_tools'), pgv.call_ref('get_tools'), pgv.esc(p_name)]);

  v_html := v_html || pgv.grid(
    pgv.stat('Pack', pgv.badge(split_part(p_name, '_', 1), 'info')),
    pgv.stat('Outil', p_name)
  );

  IF v_tool.description IS NOT NULL THEN
    v_html := v_html || '<p>' || pgv.esc(v_tool.description) || '</p>';
  END IF;

  IF v_tool.input_schema IS NOT NULL AND v_tool.input_schema ? 'properties' THEN
    v_params := v_tool.input_schema -> 'properties';
    v_html := v_html || '<h4>Parametres</h4>';
    v_html := v_html || '<md>' || E'\n';
    v_html := v_html || '| Nom | Type | Requis | Description |' || E'\n';
    v_html := v_html || '|-----|------|--------|-------------|' || E'\n';

    FOR v_key, v_prop IN SELECT * FROM jsonb_each(v_params)
    LOOP
      v_html := v_html || '| `' || v_key || '`'
        || ' | ' || coalesce(v_prop ->> 'type', '-')
        || ' | ' || CASE WHEN v_tool.input_schema -> 'required' @> to_jsonb(v_key) THEN pgv.badge('oui','warning') ELSE '-' END
        || ' | ' || coalesce(v_prop ->> 'description', '-')
        || ' |' || E'\n';
    END LOOP;
    v_html := v_html || '</md>' || E'\n';
  END IF;

  v_html := v_html || '<h4>Utilisation recente</h4>';
  v_html := v_html || '<md data-page="10">' || E'\n';
  v_html := v_html || '| Module | Action | Autorise | Raison | Date |' || E'\n';
  v_html := v_html || '|--------|--------|----------|--------|------|' || E'\n';

  SELECT v_html || coalesce(string_agg(
    '| ' || h.module
    || ' | ' || h.action
    || ' | ' || CASE WHEN h.allowed THEN pgv.badge('oui','success') ELSE pgv.badge('non','danger') END
    || ' | ' || coalesce(h.reason, '-')
    || ' | ' || to_char(h.created_at, 'DD/MM HH24:MI')
    || ' |', E'\n'
    ORDER BY h.created_at DESC
  ), '') || E'\n</md>'
  INTO v_html
  FROM workbench.hook_log h
  WHERE h.tool = p_name;

  RETURN v_html;
END;
$function$;
COMMENT ON FUNCTION workbench.get_tool(text) IS 'Tool detail view with parameters and usage stats';

CREATE OR REPLACE FUNCTION workbench.get_tools()
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_total    integer;
  v_packs    integer;
  v_html     text;
  v_tree     jsonb := '[]'::jsonb;
  v_pack     text;
  v_pack_tools jsonb;
  r          record;
  v_tool_node jsonb;
  v_params   jsonb;
  v_key      text;
  v_prop     jsonb;
  v_detail   jsonb;
BEGIN
  SELECT count(*) INTO v_total FROM workbench.toolbox_tool;
  SELECT count(DISTINCT split_part(tool_name, '_', 1)) INTO v_packs FROM workbench.toolbox_tool;

  v_html := pgv.grid(
    pgv.stat(pgv.t('workbench.stat_tools'), v_total::text),
    pgv.stat('Packs', v_packs::text)
  );

  -- Build tree: pack > tool > (description + params)
  FOR v_pack IN
    SELECT DISTINCT
      CASE
        WHEN tool_name LIKE 'pg\_%' ESCAPE '\' THEN 'plpgsql'
        WHEN tool_name LIKE 'ws\_%' ESCAPE '\' THEN 'plpgsql'
        WHEN tool_name LIKE 'fs\_%' ESCAPE '\' THEN 'docstore'
        WHEN tool_name LIKE 'gmail\_%' ESCAPE '\' THEN 'google'
        WHEN tool_name LIKE 'doc\_%' ESCAPE '\' THEN 'docman'
        ELSE 'other'
      END
    FROM workbench.toolbox_tool
    ORDER BY 1
  LOOP
    v_pack_tools := '[]'::jsonb;

    FOR r IN
      SELECT tool_name, description, input_schema
        FROM workbench.toolbox_tool
       WHERE CASE
          WHEN tool_name LIKE 'pg\_%' ESCAPE '\' THEN 'plpgsql'
          WHEN tool_name LIKE 'ws\_%' ESCAPE '\' THEN 'plpgsql'
          WHEN tool_name LIKE 'fs\_%' ESCAPE '\' THEN 'docstore'
          WHEN tool_name LIKE 'gmail\_%' ESCAPE '\' THEN 'google'
          WHEN tool_name LIKE 'doc\_%' ESCAPE '\' THEN 'docman'
          ELSE 'other'
        END = v_pack
       ORDER BY tool_name
    LOOP
      -- Build children: description + params
      v_detail := '[]'::jsonb;

      IF r.description IS NOT NULL THEN
        v_detail := v_detail || jsonb_build_object('label', r.description);
      END IF;

      IF r.input_schema IS NOT NULL AND r.input_schema ? 'properties' THEN
        v_params := r.input_schema -> 'properties';
        FOR v_key, v_prop IN SELECT * FROM jsonb_each(v_params)
        LOOP
          v_detail := v_detail || jsonb_build_object(
            'label', v_key || ' (' || coalesce(v_prop ->> 'type', '?') || ')',
            'badge', CASE
              WHEN r.input_schema -> 'required' @> to_jsonb(v_key) THEN 'requis'
              ELSE null
            END
          );
        END LOOP;
      END IF;

      -- Tool node: branch if has detail, leaf link otherwise
      IF jsonb_array_length(v_detail) > 0 THEN
        v_tool_node := jsonb_build_object(
          'label', r.tool_name,
          'children', v_detail
        );
      ELSE
        v_tool_node := jsonb_build_object(
          'label', r.tool_name,
          'href', pgv.call_ref('get_tool', jsonb_build_object('p_name', r.tool_name)),
          'badge', '?'
        );
      END IF;

      v_pack_tools := v_pack_tools || v_tool_node;
    END LOOP;

    v_tree := v_tree || jsonb_build_object(
      'label', v_pack,
      'badge', jsonb_array_length(v_pack_tools)::text,
      'open', true,
      'children', v_pack_tools
    );
  END LOOP;

  v_html := v_html || pgv.tree(v_tree);

  RETURN v_html;
END;
$function$;
COMMENT ON FUNCTION workbench.get_tools() IS 'Tool listing grouped by pack using pgv.tree() with inline description and params';

CREATE OR REPLACE FUNCTION workbench.i18n_seed()
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
  INSERT INTO pgv.i18n(lang, key, value) VALUES
    ('fr', 'workbench.brand', 'Workbench'),
    ('fr', 'workbench.nav_messages', 'Messages'),
    ('fr', 'workbench.nav_issues', 'Issues'),
    ('fr', 'workbench.nav_tools', 'Outils'),
    ('fr', 'workbench.stat_new_msg', 'Nouveaux'),
    ('fr', 'workbench.stat_new_msg_detail', 'messages non lus'),
    ('fr', 'workbench.stat_pending', 'En cours'),
    ('fr', 'workbench.stat_pending_detail', 'messages en attente'),
    ('fr', 'workbench.stat_issues', 'Issues'),
    ('fr', 'workbench.stat_issues_detail', 'ouvertes'),
    ('fr', 'workbench.stat_tools', 'Outils'),
    ('fr', 'workbench.stat_tools_detail', 'disponibles'),
    ('fr', 'workbench.title_recent_msg', 'Messages recents'),
    ('fr', 'workbench.title_messages', 'Messages'),
    ('fr', 'workbench.title_issues', 'Issues'),
    ('fr', 'workbench.title_tools', 'Outils'),
    ('fr', 'workbench.title_tool_detail', 'Detail outil'),
    ('fr', 'workbench.btn_back_messages', 'Retour messages'),
    ('fr', 'workbench.btn_back_tools', 'Retour outils'),
    ('fr', 'workbench.label_no_messages', 'Aucun message'),
    ('fr', 'workbench.label_no_issues', 'Aucune issue ouverte'),
    ('fr', 'workbench.label_no_tools', 'Aucun outil enregistre'),
    ('fr', 'workbench.title_message_detail', 'Detail message')
  ON CONFLICT DO NOTHING;
END;
$function$;
COMMENT ON FUNCTION workbench.i18n_seed() IS 'Seed i18n translations for workbench module';

CREATE OR REPLACE FUNCTION workbench.inbox_check(p_module text)
 RETURNS TABLE(id integer, from_module text, msg_type text, subject text, body text, payload jsonb, reply_to integer, priority text)
 LANGUAGE sql
 STABLE
AS $function$
  SELECT m.id, m.from_module, m.msg_type, m.subject,
         m.body, m.payload, m.reply_to, m.priority
    FROM workbench.agent_message m
   WHERE m.to_module = p_module
     AND m.status = 'new'
     AND m.priority = 'high'
   ORDER BY m.created_at DESC
   LIMIT 1;
$function$;
COMMENT ON FUNCTION workbench.inbox_check(text) IS 'Check for high-priority unread messages (PreToolUse hook delivery) — returns full message details for injection';

CREATE OR REPLACE FUNCTION workbench.inbox_new(p_module text)
 RETURNS TABLE(id integer, from_module text, msg_type text, subject text)
 LANGUAGE sql
 STABLE
AS $function$
  SELECT m.id, m.from_module, m.msg_type, m.subject
    FROM workbench.agent_message m
   WHERE m.to_module = p_module
     AND m.status = 'new'
   ORDER BY m.created_at
   LIMIT 10;
$function$;
COMMENT ON FUNCTION workbench.inbox_new(text) IS 'Get new (unread) messages for a module — used by Stop hook';

CREATE OR REPLACE FUNCTION workbench.inbox_pending(p_module text)
 RETURNS TABLE(id integer, from_module text, msg_type text, subject text, priority text)
 LANGUAGE sql
 STABLE
AS $function$
  SELECT m.id, m.from_module, m.msg_type, m.subject, m.priority
    FROM workbench.agent_message m
   WHERE m.to_module = p_module
     AND m.status IN ('new', 'acknowledged')
   ORDER BY
     CASE WHEN m.priority = 'high' THEN 0 ELSE 1 END,
     m.created_at DESC
   LIMIT 10;
$function$;
COMMENT ON FUNCTION workbench.inbox_pending(text) IS 'Pending messages for a module — priority-sorted (SessionStart hook)';

CREATE OR REPLACE FUNCTION workbench.log_hook(p_module text, p_tool text, p_action text, p_allowed boolean, p_reason text DEFAULT NULL::text)
 RETURNS void
 LANGUAGE sql
AS $function$
  INSERT INTO workbench.hook_log (module, tool, action, allowed, reason)
    VALUES (p_module, p_tool, p_action, p_allowed, p_reason);
$function$;
COMMENT ON FUNCTION workbench.log_hook(text,text,text,boolean,text) IS 'Log a hook event (fire-and-forget)';

CREATE OR REPLACE FUNCTION workbench.nav_items()
 RETURNS jsonb
 LANGUAGE sql
 STABLE
AS $function$
  SELECT jsonb_build_array(
    jsonb_build_object('label', pgv.t('workbench.nav_messages'), 'href', pgv.call_ref('get_messages')),
    jsonb_build_object('label', pgv.t('workbench.nav_issues'),   'href', pgv.call_ref('get_issues')),
    jsonb_build_object('label', pgv.t('workbench.nav_tools'),    'href', pgv.call_ref('get_tools')),
    jsonb_build_object('label', 'Primitives',                    'href', pgv.call_ref('get_primitives'))
  );
$function$;
COMMENT ON FUNCTION workbench.nav_items() IS 'Navigation menu items for workbench module';

CREATE OR REPLACE FUNCTION workbench.on_issue_report_insert()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_msg_id integer;
BEGIN
  INSERT INTO workbench.agent_message(from_module, to_module, msg_type, subject, body, priority, payload)
  VALUES (
    'shell',
    'lead',
    'issue_report',
    format('Issue #%s à traiter (%s)', NEW.id, NEW.issue_type),
    format('SELECT * FROM workbench.issue_report WHERE id = %s', NEW.id),
    CASE WHEN NEW.issue_type = 'bug' THEN 'high' ELSE 'normal' END,
    jsonb_build_object('issue_id', NEW.id)
  )
  RETURNING id INTO v_msg_id;

  -- Link issue to message and acknowledge
  NEW.message_id := v_msg_id;
  NEW.status := 'acknowledged';

  RETURN NEW;
END;
$function$;
COMMENT ON FUNCTION workbench.on_issue_report_insert() IS 'Trigger: crée agent_message, lie issue↔message, passe en acknowledged';

CREATE OR REPLACE FUNCTION workbench.postgrest_pre_request()
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_tenant text;
BEGIN
  -- Try JWT claim first (production), fallback to 'dev' (development)
  v_tenant := coalesce(
    current_setting('request.jwt.claims', true)::jsonb ->> 'tenant_id',
    'dev'
  );
  PERFORM set_config('app.tenant_id', v_tenant, true);
END;
$function$;
COMMENT ON FUNCTION workbench.postgrest_pre_request() IS 'PostgREST pre-request hook: set tenant context from JWT claim or default to dev';

CREATE OR REPLACE FUNCTION workbench.session_create(p_module text, p_pid integer)
 RETURNS integer
 LANGUAGE sql
AS $function$
  INSERT INTO workbench.agent_session (module, status, pid, started_at)
    VALUES (p_module, 'running', p_pid, now())
    RETURNING id;
$function$;
COMMENT ON FUNCTION workbench.session_create(text,integer) IS 'Create agent session record, return id';

CREATE OR REPLACE FUNCTION workbench.session_end(p_id integer, p_status text)
 RETURNS void
 LANGUAGE sql
AS $function$
  UPDATE workbench.agent_session
    SET status = p_status, ended_at = now()
    WHERE id = p_id;
$function$;
COMMENT ON FUNCTION workbench.session_end(integer,text) IS 'End an agent session with status';

